SELECT '0' EXPECTED_STATE, COUNT(*) ACTUAL_COUNT FROM IBC_ISSUER_FILE_TYPE_FIELDS WHERE ID_ISSUER = 999 AND ID_FILE_TYPE = (SELECT ID_FILE_TYPE FROM TFM_FILE_TYPE WHERE TYPE_NAME = 'DATA_DUMP_RPT_PAYMENT_MEDIA') AND FIELD IN ('CardNumber', 'Document', 'InternalAccountNumber', 'StatusCode', 'IssueDate', 'InactiveDate', 'DueDate', 'SecuenceNumber', 'DocumentType', 'DocTypeDescription', 'Category', 'ProductCode', 'ProductDescription', 'ProductGroupCode', 'TrackingID', 'PaymentMediaStatusType', 'EmbossedName', 'Scheme', 'CardTechnology', 'SDP', 'BlockStatusCode', 'BlockCategoryCode', 'Bin', 'ICA', 'ChipSequence', 'EmisionTime', 'PreviusDueDate', 'ActionTaken');


